const AWS = require('aws-sdk');
const path = require('path');

// Load AWS credentials from the shared credentials file
AWS.config.loadFromPath('/root/.aws/credentials');

// Override region if not set in credentials
if (!AWS.config.region) {
  AWS.config.update({ region: 'us-east-1' });
}

module.exports = AWS;

const AWS = require('./config');

const s3 = new AWS.S3();

async function uploadFile(bucket, key, body) {
  const params = {
    Bucket: bucket,
    Key: key,
    Body: body
  };
  try {
    const result = await s3.upload(params).promise();
    console.log('Upload successful:', result.Location);
    return result;
  } catch (err) {
    console.error('S3 upload failed:', err.message);
    throw err;
  }
}

async function listBuckets() {
  try {
    const data = await s3.listBuckets().promise();
    return data.Buckets;
  } catch (err) {
    console.error('Failed to list buckets:', err.message);
    throw err;
  }
}

module.exports = { uploadFile, listBuckets };
